type commitOutcomeFailure struct {
	operation string
	assignee  string
	result    *ExecuteBeadLoopResult
	err       error
}

func (e *commitOutcomeFailure) Error() string {
	return e.err.Error()
}

func commitOutcomeError(operation, assignee string, result *ExecuteBeadLoopResult, err error) error {
	if err == nil {
		return nil
	}
	return &commitOutcomeFailure{
		operation: operation,
		assignee:  assignee,
		result:    result,
		err:       err,
	}
}

// commitOutcome keeps the drain loop moving after a post-outcome store failure.
// The wrapped op supplies the operation label via commitOutcomeError so this
// helper can preserve the loop-error event and cooldown behavior without
// hard-erroring the worker or surfacing the store error to Drain.
func commitOutcome(ctx context.Context, store ExecuteBeadLoopStore, beadID string, op func() error) error {
	if err := op(); err != nil {
		var failure *commitOutcomeFailure
		if errors.As(err, &failure) {
			if failure.result != nil {
				failure.result.Failures++
				failure.result.LastFailureStatus = "loop-error"
			}
			_ = store.AppendEvent(beadID, bead.BeadEvent{
				Kind:      "loop-error",
				Summary:   failure.operation + " failed",
				Body:      failure.err.Error(),
				Actor:     failure.assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: time.Now().UTC(),
			})
			_ = store.SetExecutionCooldown(beadID, time.Now().UTC().Add(StoreErrorCooldown), "loop-error", failure.operation+": "+failure.err.Error())
			return nil
		}
		_ = store.SetExecutionCooldown(beadID, time.Now().UTC().Add(StoreErrorCooldown), "loop-error", err.Error())
		return nil
	}
	return nil
}

	}
}

// classifyDisruption examines the loop ctx and the executor's error to decide
// whether a failed ExecuteBead attempt was caused by external disruption
// (worker killed, context cancelled, transport error) rather than the model
// genuinely producing nothing. Returns ok=true plus a short reason kind when
// disruption is detected; the caller marks the report Disrupted to bypass the
// no-progress cooldown (ddx-5b3e57f4). Reason kinds are stable strings used
// in the disruption_detected event:
//
//	context_canceled, context_deadline, transport_error
func classifyDisruption(ctx context.Context, executorErr error) (string, bool) {
	if ctx != nil {
		switch ctx.Err() {
		case context.Canceled:
			return "context_canceled", true
		case context.DeadlineExceeded:
			return "context_deadline", true
		}
	}
	if executorErr == nil {
		return "", false
	}
	if isTransportError(executorErr) {
		return "transport_error", true
	}
	return "", false
}

// isTransportError returns true when err looks like a transport-class failure
// (network reset, connection refused, TLS error, gateway, provider 5xx). The
// signal is fuzzy on purpose: callers (classifyDisruption) only use it to
// flag a failure as Disrupted so the bead skips the long no-progress cooldown
// and is retried promptly. False positives are cheap (one quick retry); false
// negatives are expensive (6h park for a transient outage).
func isTransportError(err error) bool {
	if err == nil {
		return false
	}
	msg := strings.ToLower(err.Error())
	for _, marker := range []string{
		"connection refused",
		"connection reset",
		"connection closed",
		"no route to host",
		"network is unreachable",
		"i/o timeout",
		"context deadline exceeded",
		"tls handshake",
		"eof",
		"broken pipe",
		"bad gateway",
		"service unavailable",
		"gateway timeout",
		"transport",
	} {
		if strings.Contains(msg, marker) {
			return true
		}
	}
	return false
}

// emitDisruptionDetected records a structured `disruption_detected` event for
// the bead and the loop event sink so operators can see disruption rates and
// which class is firing (ddx-5b3e57f4 AC #5).
func emitDisruptionDetected(emit func(string, map[string]any), store BeadEventAppender, beadID, reason, detail, harness, model, assignee string, now time.Time) {
	emit("disruption_detected", map[string]any{
		"bead_id": beadID,
		"reason":  reason,
		"detail":  detail,
		"harness": harness,
		"model":   model,
	})
	if store == nil || beadID == "" {
		return
	}
	body, err := json.Marshal(map[string]any{
		"reason":  reason,
		"detail":  detail,
		"harness": harness,
		"model":   model,
	})
	bodyStr := detail
	if err == nil {
		bodyStr = string(body)
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "disruption_detected",
		Summary:   reason,
		Body:      bodyStr,
		Actor:     assignee,
		Source:    "ddx agent execute-loop",
		CreatedAt: now,
	})
}

